// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('hover', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('hover', async function() {
    await driver.get("http://localhost:4200/user/department-goal/");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    await driver.sleep(3000);
    {
      const element = await driver.findElement(By.css(".ant-table-row:nth-child(1) > .ant-table-cell:nth-child(1)"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    vars["backgroundColor"] = await driver.executeScript("return getComputedStyle(document.getElementsByClassName(\'ant-table-cell\')[4]).backgroundColor.toString().substr(0, 18)+\')\'");
    assert(vars["backgroundColor"].toString() == "rgba(230, 255, 233)");
  });
});
